void solve(int CASE)
{
	int n; cin >> n;
	var ans = vector<int>(n + 1);
	var g = vector<vector<pii>>(n + 1);
	var deg = vector<int>(n + 1);
	fa(i, 1, n) {
		int k; cin >> k;
		if (k & 1) {
			int x; cin >> x;
			g[x].pb({ 0,i });
			deg[x]++;
		}
		else {
			int x, y; cin >> x >> y;
			g[x].pb({ y,i });
			g[y].pb({ x,i });
			deg[x]++;
			deg[y]++;
		}
	}

	var Q = queue<int>();
	fa(i, 1, n)if (deg[i] == 1)Q.push(i);
	while (Q.size()) {
		int now = Q.front();
		Q.pop();
		for (var& [to, eid] : g[now])if (!ans[eid]) {
			deg[to]--;
			deg[now]--;
			ans[eid] = now;
			if (deg[to] == 1)Q.push(to);
			break;
		}
	}

	fa(i, 1, n)if (deg[i]) {
		int now = i;
		while (deg[now]) {
			for (var& [to, eid] : g[now])if (!ans[eid]) {
				deg[to]--;
				deg[now]--;
				ans[eid] = now;
				now = to;
				break;
			}
		}
	}

	fa(i, 1, n)if (!ans[i]) {
		cout << "kou is angry" << endl;
		return;
	}
	fa(i, 1, n)cout << ans[i] << " \n"[i == n];
	return;
}
